import React, { useState } from "react";
// import { Field, reduxForm } from "redux-form";
import {
	Segment,
	Container,
	Input,
	Button,
	Form as F
} from "semantic-ui-react";
import { connect } from "react-redux";
import { compose } from "redux";
import { firestoreConnect } from "react-redux-firebase";
// import store from "../store/store";
import { Formik, Form, ErrorMessage } from "formik";
import * as yup from "yup";
import { debounce } from "lodash";

const validationSchema = yup.object().shape({
	title: yup
		.string()
		.min(4, "Too Short!")
		.max(50, "Too Long!")
		.required()
		.label("Title"),
	slug: yup
		.string()
		.min(4, "Too Short!")
		.max(50, "Too Long!")
		.matches(/^[a-z0-9]+(?:-[a-z0-9]+)*$/, {
			message:
				"Invalid slug address as slug should by lowercased and words spareted only with ( - ) hint: adobe-photoshop"
		})
		.required()
		.label("Slug"),
	description: yup
		.string()
		.required()
		.label("Description")
});

const FieldWrapper = ({ control, formikKey, formikProps, ...rest }) => (
	<React.Fragment>
		<F.Field
			error={
				formikProps.touched[formikKey] &&
				formikProps.errors[formikKey] &&
				true
			}
			control={control}
			value={formikProps.values[formikKey]}
			onChange={formikProps.handleChange(formikKey)}
			onBlur={formikProps.handleBlur(formikKey)}
			{...rest}
		/>
		<ErrorMessage name={formikKey} />
	</React.Fragment>
);

const CreateCourse = props => {
	const [v, setV] = useState(false);
	function slugify(string) {
		return string
			.toString()
			.trim()
			.toLowerCase()
			.replace(/\s+/g, "-")
			.replace(/[^\w\-]+/g, "")
			.replace(/\-\-+/g, "-")
			.replace(/^-+/, "")
			.replace(/-+$/, "");
	}

	const handleSlug = (value, formikProps) => {
		formikProps.setFieldValue("slug", value, true);
		formikProps.setFieldTouched("slug", true);
		setV(true);
		// const check = debounce((props, value, formikProps ) => {
			const sleep = ms => new Promise(resolve => setTimeout(resolve, ms));
			sleep(2000)
				.then(() => {
			if (props.courses.map(x => x.id).includes(value)) {
				formikProps.setFieldError("slug", "This slug is already taken");
			}
			})
			.then(() => {
			setV(false);
			});
		// }, 500);
		// check(props, value, formikProps);
	};

	const handleTitle = (value, formikProps) => {
		const slug = slugify(value);
		formikProps.setFieldValue("title", value, true);
		formikProps.setFieldTouched("title", true);
		handleSlug(slug, formikProps);
	};

	return (
		<Container>
			<h1>Create New Course</h1>
			<Formik
				initialValues={{
					title: "",
					slug: "",
					description: ""
				}}
				onSubmit={values => {
					// same shape as initial values
					console.log(values);
				}}
				validationSchema={validationSchema}
				// validate={asyncValidate}
				render={formikProps => (
					<F
						onSubmit={formikProps.handleSubmit}
						onReset={formikProps.handleReset}
					>
						<FieldWrapper
							label="Title"
							placeholder="Course Title"
							formikProps={formikProps}
							formikKey="title"
							onChange={e =>
								handleTitle(e.target.value, formikProps)
							}
							onBlur={e =>
								handleTitle(e.target.value, formikProps)
							}
							control="input"
						/>
						<FieldWrapper
							loading={v}
							icon={
								v === false &&
								formikProps.touched.slug &&
								formikProps.errors.slug === undefined
									? {
											name: "check circle",
											color: "green"
									  }
									: null
							}
							label="Slug"
							control={Input}
							placeholder="Course address"
							formikProps={formikProps}
							formikKey="slug"
							onChange={e => handleSlug(e.target.value, formikProps)}
							onBlur={e => handleSlug(e.target.value, formikProps)}
						/>
						<FieldWrapper
							label="Description"
							placeholder="Course Description"
							formikProps={formikProps}
							formikKey="description"
							control="textarea"
						/>
						<Button
							type="submit"
							disabled={formikProps.isValidating || v || formikProps.isSubmiting }
						>
							Submit
						</Button>
						<Button type="reset">Reset</Button>
					</F>
				)}
			/>
		</Container>
	);
};

const mapStateToProps = state => {
	return {
		courses: state.firestore.ordered.courses
	};
};

export default compose(
	connect(mapStateToProps),
	firestoreConnect([{ collection: "courses" }])
)(CreateCourse);
